// Process and normalize extraction results
const input = $input.first().json;

// Determine source of data
let extractedText = '';
let processingMethod = '';
let confidence = 1.0;
let processingTime = 0;
let engineUsed = 'direct';

// Check if this came from OCR or direct extraction
if (input.text && input.confidence_score !== undefined) {
  // OCR result
  extractedText = input.text || input.extracted_text || '';
  processingMethod = 'ocr_processing';
  confidence = input.confidence_score || 0;
  processingTime = input.processing_time || 0;
  engineUsed = input.engine_used || 'unknown';
} else {
  // Direct text extraction result
  extractedText = input.text || '';
  processingMethod = 'direct_text_extraction';
  confidence = 1.0;
  processingTime = 0.1;
  engineUsed = 'direct';
}

// Get Ollama response
const ollamaResponse = input.response || input.text || '';

try {
  // Try to parse JSON from Ollama response
  let extractedData;

  // Clean response - remove markdown code blocks if present
  const cleanResponse = ollamaResponse
    .replace(/```json\s*/g, '')
    .replace(/```\s*/g, '')
    .trim();

  try {
    extractedData = JSON.parse(cleanResponse);
  } catch (parseError) {
    // If JSON parsing fails, try to extract JSON from text
    const jsonMatch = cleanResponse.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      extractedData = JSON.parse(jsonMatch[0]);
    } else {
      throw new Error('No valid JSON found in response');
    }
  }

  // Build final result - preserve original data structure and add extraction
  const result = {
    ...($('check-text-empty').first().json || {}), // Original data
    text: extractedText, // Update text field with OCR result if applicable
    extracted_invoice_data: extractedData,
    processing_metadata: {
      method: processingMethod,
      confidence_score: confidence,
      processing_time_seconds: processingTime,
      engine_used: engineUsed,
      extraction_model: 'llama3.2:latest',
      timestamp: new Date().toISOString()
    }
  };

  return { json: result };

} catch (error) {
  // Return error response but preserve original data
  return {
    json: {
      ...($('check-text-empty').first().json || {}),
      text: extractedText,
      extracted_invoice_data: null,
      processing_metadata: {
        method: processingMethod,
        confidence_score: confidence,
        error: error.message,
        raw_response: ollamaResponse,
        timestamp: new Date().toISOString()
      }
    }
  };
}
